"use client";

import * as React from "react";

import { cn } from "@/lib/utils";
import { damp, useExperienceViewport, usePrefersReducedMotion } from "@/components/experience/experience-runtime";

export type MarqueeVelocityProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  children: React.ReactNode;
  /** Base travel speed in pixels per second. */
  speed?: number;
  /** 1 moves left-to-right content leftwards, -1 the other way. */
  direction?: 1 | -1;
  /** How strongly scroll velocity boosts the marquee (0 disables the coupling). */
  velocityInfluence?: number;
  /** Cap for the velocity boost multiplier. */
  maxBoost?: number;
  /** Reverse travel while the user scrolls upward. */
  flipOnScroll?: boolean;
  /** Ease the strip to a stop while hovered. */
  pauseOnHover?: boolean;
  gap?: number;
  trackClassName?: string;
  contentClassName?: string;
};

/**
 * An infinite marquee whose speed and direction react to scroll velocity.
 * Reduced-motion users get a static, natively scrollable strip.
 */
export function MarqueeVelocity({
  children,
  className,
  contentClassName,
  direction = 1,
  flipOnScroll = true,
  gap = 48,
  label,
  maxBoost = 4,
  pauseOnHover = false,
  speed = 80,
  trackClassName,
  velocityInfluence = 1.6,
  ...props
}: MarqueeVelocityProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const trackRef = React.useRef<HTMLDivElement>(null);
  const contentRef = React.useRef<HTMLDivElement>(null);
  const hoveredRef = React.useRef(false);
  const [copies, setCopies] = React.useState(2);
  const reducedMotion = usePrefersReducedMotion();
  const viewport = useExperienceViewport();
  const activeSpeed = speed * (viewport === "mobile" ? .68 : viewport === "tablet" ? .84 : 1);
  const activeGap = gap * (viewport === "mobile" ? .58 : viewport === "tablet" ? .78 : 1);

  React.useEffect(() => {
    const root = rootRef.current;
    const track = trackRef.current;
    const content = contentRef.current;
    if (!root || !track || !content || reducedMotion) return;

    let disposed = false;
    let frame = 0;
    let previous = performance.now();
    let offset = 0;
    let contentWidth = Math.max(1, content.offsetWidth + activeGap);
    let onScreen = true;
    let lastScrollY = window.scrollY;
    let smoothedScrollVelocity = 0;
    let pauseFactor = 1;

    const measure = () => {
      contentWidth = Math.max(1, content.offsetWidth + activeGap);
      const needed = Math.max(2, Math.ceil((root.clientWidth * 2) / contentWidth) + 1);
      setCopies((current) => (current === needed ? current : needed));
    };
    const resizeObserver = new ResizeObserver(measure);
    resizeObserver.observe(root);
    resizeObserver.observe(content);
    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
      },
      { rootMargin: "10% 0px" },
    );
    intersectionObserver.observe(root);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      if (onScreen && document.visibilityState === "visible") {
        const scrollY = window.scrollY;
        const scrollVelocity = (scrollY - lastScrollY) / delta;
        lastScrollY = scrollY;
        smoothedScrollVelocity = damp(smoothedScrollVelocity, scrollVelocity, 8, delta);
        pauseFactor = damp(pauseFactor, pauseOnHover && hoveredRef.current ? 0 : 1, 10, delta);

        const boost = Math.min(maxBoost, Math.abs(smoothedScrollVelocity) * (velocityInfluence / 1000));
        let travelDirection = direction;
        if (flipOnScroll && smoothedScrollVelocity < -40) travelDirection = (direction * -1) as 1 | -1;
        offset -= travelDirection * activeSpeed * (1 + boost) * pauseFactor * delta;
        offset = ((offset % contentWidth) + contentWidth) % contentWidth;
        track.style.transform = `translate3d(${-offset}px, 0, 0)`;
      }
      frame = requestAnimationFrame(render);
    };

    measure();
    frame = requestAnimationFrame(render);
    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
    };
  }, [activeGap, activeSpeed, direction, flipOnScroll, maxBoost, pauseOnHover, reducedMotion, velocityInfluence]);

  if (reducedMotion) {
    return (
      <section aria-label={label} data-marquee-velocity data-experience-viewport={viewport} data-static className={cn("relative overflow-x-auto", className)} {...props}>
        <div className={cn("flex w-max items-center", contentClassName)} style={{ gap: activeGap }}>
          {children}
        </div>
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-marquee-velocity
      data-experience-viewport={viewport}
      className={cn("relative overflow-hidden", className)}
      onPointerEnter={() => {
        hoveredRef.current = true;
      }}
      onPointerLeave={() => {
        hoveredRef.current = false;
      }}
      {...props}
    >
      <div ref={trackRef} className={cn("flex w-max items-center will-change-transform", trackClassName)} style={{ gap: activeGap }}>
        {Array.from({ length: copies }, (_, index) => (
          <div
            key={index}
            ref={index === 0 ? contentRef : undefined}
            aria-hidden={index > 0 || undefined}
            className={cn("flex shrink-0 items-center", contentClassName)}
            style={{ gap: activeGap }}
          >
            {children}
          </div>
        ))}
      </div>
    </section>
  );
}

"use client";

import * as React from "react";

export const EXPERIENCE_BREAKPOINTS = {
  tablet: 640,
  desktop: 1025,
} as const;

export type ExperienceViewport = "mobile" | "tablet" | "desktop";

export type ExperienceResponsiveValue<T> = T | {
  /** Mobile-first value, also used during SSR/hydration. */
  mobile: T;
  /** iPad/tablet value. Falls back to `mobile` when omitted. */
  tablet?: T;
  /** Wide-screen value. Falls back to `tablet`, then `mobile`. */
  desktop?: T;
};

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

/**
 * Shared mobile-first viewport contract for every experience primitive.
 *
 * Mobile: < 640px · tablet/iPad: 640–1024px · desktop: >= 1025px.
 * Pointer capability remains a separate signal because an iPad can gain a
 * trackpad without changing its layout profile.
 */
export function useExperienceViewport(): ExperienceViewport {
  const tablet = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.tablet}px)`);
  const desktop = useMediaQuery(`(min-width: ${EXPERIENCE_BREAKPOINTS.desktop}px)`);
  if (desktop) return "desktop";
  if (tablet) return "tablet";
  return "mobile";
}

export function resolveExperienceValue<T>(
  value: ExperienceResponsiveValue<T>,
  viewport: ExperienceViewport,
): T {
  if (typeof value !== "object" || value === null || !("mobile" in value)) return value;
  if (viewport === "desktop") return value.desktop ?? value.tablet ?? value.mobile;
  if (viewport === "tablet") return value.tablet ?? value.mobile;
  return value.mobile;
}

/** Conservative raster/WebGL supersampling budget for each layout profile. */
export function getExperienceDprCap(width: number) {
  if (width < EXPERIENCE_BREAKPOINTS.tablet) return 1;
  if (width < EXPERIENCE_BREAKPOINTS.desktop) return 1.25;
  return 1.6;
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
